import { useState, useEffect } from 'react';
import React from 'react';
import './Chatting.css';
import { MainContainer, ChatContainer, MessageList, Message, MessageInput } from '@chatscope/chat-ui-kit-react';
import '@chatscope/chat-ui-kit-styles/dist/default/styles.min.css';
import Modal from './modal';

const Chatting = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);

  // ✅ 모달 열기/닫기 토글 함수
  const toggleModal = () => {
    setIsModalOpen((prev) => !prev);
  };

  // ✅ `.cs-message-input > div:first-child` 클릭 시 모달 열기 (정확한 타이밍 설정)
  useEffect(() => {
    const addClickEvent = () => {
      const messageInputDiv = document.querySelector('.cs-message-input > div:first-child');
      if (messageInputDiv) {
        messageInputDiv.addEventListener('click', toggleModal);
      }
    };

    // ✅ `setTimeout`을 사용하여 DOM이 렌더링된 후 요소 찾기
    const timeout = setTimeout(addClickEvent, 100);

    return () => {
      clearTimeout(timeout); // ✅ 타이머 클리어
      const messageInputDiv = document.querySelector('.cs-message-input > div:first-child');
      if (messageInputDiv) {
        messageInputDiv.removeEventListener('click', toggleModal);
      }
    };
  }, []);

  return (
    <div className='chatting'>
      <MainContainer>
        <ul>
          <li className='name'>사용자가 지정한 애칭</li>
          <li style={{ width: 786, height: 827 }}>
            <ChatContainer>
              <MessageList style={{ marginTop: 15 }}>
                <Message model={{ message: '안녕', direction: 'incoming', position: 'first' }} />
                <Message model={{ message: '나도 안녕', direction: 'outgoing', position: 'first' }} />
              </MessageList>
              <MessageInput placeholder="메세지 작성" />
            </ChatContainer>
          </li>
        </ul>
        {isModalOpen && <Modal isOpen={isModalOpen} onClose={toggleModal} />}
      </MainContainer>
    </div>
  );
};

export default Chatting;
